305→    leaves(forward = false)
306→        .firstOrNull { it.isWhiteSpaceWithNewline() }
307→        ?.text
308→        ?.substringAfterLast('\n')
309→        .orEmpty() // Fallback if node is not preceded by any newline character
310→        .applyIf(includeNewline) { prefixIfNot("\n") }
