public fun ASTNode.leavesOnLine(): Sequence<ASTNode> {
    val lastLeafOnLineOrNull = getLastLeafOnLineOrNull()
    return getFirstLeafOnLineOrSelf()
        .leavesIncludingSelf()
        .takeWhile { lastLeafOnLineOrNull == null || it.prevLeaf() != lastLeafOnLineOrNull }
